        lines = text.splitlines() or [""]
        longest = max(len(l) for l in lines)
        return max(1, int(longest * fs * 0.56)), max(fs, int(len(lines) * fs * 1.2)), max(1, int(fs * 0.85))

    def _base(self, t: str, x: float, y: float, w: float, h: float, stroke: str, bg: str, sw: int, round_rect: bool, link: Optional[str]) -> Dict[str, Any]:
        seed = 1000 + self.i * 37
        nonce = int(hashlib.sha256(str(seed).encode()).hexdigest()[:8], 16)
        e = {
            "id": self._id("r" if t == "rectangle" else "e"),
            "type": t, "x": self._q(x), "y": self._q(y), "width": self._q(w), "height": self._q(h), "angle": 0,
            "strokeColor": stroke, "backgroundColor": bg, "fillStyle": "solid", "strokeWidth": sw, "strokeStyle": "solid",
            "roughness": 0, "opacity": 100, "seed": seed, "version": 1, "versionNonce": nonce, "isDeleted": False,
            "groupIds": [], "frameId": None, "roundness": {"type": 3} if (t == "rectangle" and round_rect) else None,
            "boundElements": None, "updated": TS, "link": link, "locked": False,
        }
        self.elements.append(e)
        return e

    def rect(self, x: float, y: float, w: float, h: float, stroke: str, fill: str, sw: int = 1, rounded: bool = True, link: Optional[str] = None) -> Dict[str, Any]:
        return self._base("rectangle", x, y, w, h, stroke, fill, sw, rounded, link)

    def ellipse(self, x: float, y: float, w: float, h: float, stroke: str, fill: str, sw: int = 1, link: Optional[str] = None) -> Dict[str, Any]:
        return self._base("ellipse", x, y, w, h, stroke, fill, sw, False, link)

    def text(self, text: str, x: float, y: float, color: str, fs: int = 14, link: Optional[str] = None) -> Dict[str, Any]:
        w, h, bl = self._txt_size(text, fs)
        seed = 1000 + self.i * 37
        nonce = int(hashlib.sha256(str(seed).encode()).hexdigest()[:8], 16)
        e = {
            "id": self._id("t"), "type": "text", "x": self._q(x), "y": self._q(y), "width": w, "height": h, "angle": 0,
            "strokeColor": color, "backgroundColor": "transparent", "fillStyle": "solid", "strokeWidth": 1, "strokeStyle": "solid",
            "roughness": 0, "opacity": 100, "seed": seed, "version": 1, "versionNonce": nonce, "isDeleted": False,
            "groupIds": [], "frameId": None, "roundness": None, "boundElements": None, "updated": TS, "link": link, "locked": False,
            "text": text, "fontSize": fs, "fontFamily": 2, "textAlign": "left", "verticalAlign": "top", "baseline": bl,
        }
        self.elements.append(e)
        return e

    def out(self) -> Dict[str, Any]:
        return {
            "type": "excalidraw",
            "version": 2,
            "source": "https://excalidraw.com",
            "elements": self.elements,
            "appState": {"viewBackgroundColor": "#F7F7F7", "gridSize": None},
            "files": {},
        }


def validate_dsl(dsl: Dict[str, Any]) -> None:
    errs: List[str] = []
    for k in ("screens", "modals", "dialogs"):
        if k not in dsl:
            errs.append(f"Missing '{k}'.")
        elif not isinstance(dsl[k], list):
            errs.append(f"'{k}' must be an array.")
    screens = dsl.get("screens", []) if isinstance(dsl.get("screens"), list) else []
    modals = dsl.get("modals", []) if isinstance(dsl.get("modals"), list) else []
    dialogs = dsl.get("dialogs", []) if isinstance(dsl.get("dialogs"), list) else []
    ids: List[str] = []
    for s in screens:
        sid = s.get("id")
        if not isinstance(sid, str) or not SCREEN_ID_RE.match(sid):
            errs.append(f"Invalid screen id: {sid!r}")
        else:
            ids.append(sid)
    screen_ids = set(ids)
    for arr, rgx, lbl in ((modals, MODAL_ID_RE, "modal"), (dialogs, DIALOG_ID_RE, "dialog")):
        for obj in arr:
            cid = obj.get("id")
            if not isinstance(cid, str) or not rgx.match(cid):
                errs.append(f"Invalid {lbl} id: {cid!r}")
            else:
                ids.append(cid)
            if obj.get("parentScreen") not in screen_ids:
                errs.append(f"{lbl} '{cid}' has unknown parentScreen '{obj.get('parentScreen')}'.")
    dup = sorted({x for x in ids if ids.count(x) > 1})
    errs.extend([f"Duplicate canvas id '{d}'." for d in dup])
    targets = set(ids)

    def _validate_table_button(btn: Any, p: str) -> None:
        if not isinstance(btn, dict):
            errs.append(f"{p}: button must be object.")
            return
        txt = btn.get("txt")
        color = btn.get("c")
        act = btn.get("act")
        if not isinstance(txt, str) or not txt.strip():
            errs.append(f"{p}: button.txt must be non-empty string.")
        if color not in VALID_COLORS:
            errs.append(f"{p}: button.c invalid color '{color}'.")
        if act is None:
            return
        if not isinstance(act, dict):
            errs.append(f"{p}: button.act must be object when present.")
            return
        if act.get("type") != "navigate":
            errs.append(f"{p}: button.act.type must be 'navigate' when act is present.")
            return
        target = _normalized_target(act.get("target"))
        if target is not None and target not in targets:
            errs.append(f"{p}: button.act invalid target '{target}'.")

    def check_e(e: Dict[str, Any], p: str) -> None:
        if e.get("t") not in VALID_TYPES:
            errs.append(f"{p}: invalid type '{e.get('t')}'.")
        if e.get("c") not in VALID_COLORS:
            errs.append(f"{p}: invalid color '{e.get('c')}'.")
        if e.get("t") == "text" and e.get("tc") not in VALID_TEXT_COLORS:
            errs.append(f"{p}: text element requires valid tc.")
        if e.get("t") != "text" and e.get("tc") is not None:
            errs.append(f"{p}: tc only allowed on text.")
        for k in ("x", "y", "w", "h"):
            v = e.get(k)
            if not isinstance(v, int):
                errs.append(f"{p}: '{k}' must be integer.")
            elif v < 0 or v > 1000:
                errs.append(f"{p}: '{k}' out of range [0,1000].")
        act = e.get("act")
        if act is not None:
            if not isinstance(act, dict):
                errs.append(f"{p}: act must be object when present.")
            elif act.get("type") != "navigate":
                errs.append(f"{p}: act.type must be 'navigate' when act is present.")
            else:
                target = _normalized_target(act.get("target"))
                if target is not None and target not in targets:
                    errs.append(f"{p}: invalid act target '{target}'.")
        if e.get("t") == "table":
            items = e.get("items")
            if not isinstance(items, dict):
                errs.append(f"{p}: table requires items object.")
            else:
                cols = items.get("columns")
                row = items.get("row")
                if not isinstance(cols, list):
                    errs.append(f"{p}: table requires items.columns.")
                    cols = []
                if not isinstance(row, list):
                    errs.append(f"{p}: table requires items.row.")
                    row = []

                col_ids: List[str] = []
                col_by_id: Dict[str, Dict[str, Any]] = {}
                for i, c in enumerate(cols):
                    if not isinstance(c, dict):
                        errs.append(f"{p}.items.columns[{i}] must be object.")
                        continue
                    cid = c.get("id")
                    label = c.get("label")
                    ctype = c.get("type")
                    if not isinstance(cid, str) or not cid.strip():
                        errs.append(f"{p}.items.columns[{i}]: id must be non-empty string.")
                        continue
                    if cid in col_by_id:
                        errs.append(f"{p}.items.columns[{i}]: duplicate column id '{cid}'.")
                        continue
                    if not isinstance(label, str) or not label.strip():
                        errs.append(f"{p}.items.columns[{i} ({cid})]: label must be non-empty string.")
                    if ctype not in TABLE_COLUMN_TYPES:
                        errs.append(f"{p}.items.columns[{i} ({cid})]: invalid type '{ctype}'.")
                    if ctype == "button":
                        buttons = c.get("buttons")
                        if not isinstance(buttons, list) or len(buttons) < 1:
                            errs.append(f"{p}.items.columns[{i} ({cid})]: button column requires buttons array.")
                        else:
                            for bi, b in enumerate(buttons):
                                _validate_table_button(b, f"{p}.items.columns[{i} ({cid})].buttons[{bi}]")
                    if ctype == "dropdown":
                        options = _extract_dropdown_options(c.get("items"))
                        if len(options) < 1:
                            errs.append(f"{p}.items.columns[{i} ({cid})]: dropdown column requires non-empty items array.")
                    col_ids.append(cid)
                    col_by_id[cid] = c

                if isinstance(row, list) and isinstance(cols, list):
                    if len(row) != len(cols):
                        errs.append(
                            f"{p}.items.row: must contain same number of entries as columns "
                            f"({len(row)} != {len(cols)})."
                        )
                    seen_cols: List[str] = []
                    for ri, cell in enumerate(row):
                        if not isinstance(cell, dict):
                            errs.append(f"{p}.items.row[{ri}] must be object.")
                            continue
                        cid = cell.get("column")
                        if not isinstance(cid, str) or not cid.strip():
                            errs.append(f"{p}.items.row[{ri}]: 'column' must be non-empty string.")
                            continue
                        seen_cols.append(cid)
                        col = col_by_id.get(cid)
                        if col is None:
                            errs.append(f"{p}.items.row[{ri}]: unknown column '{cid}'.")
                            continue
                        ctype = col.get("type")
                        if ctype == "text":
                            if not isinstance(cell.get("value"), str):
                                errs.append(f"{p}.items.row[{ri}] ({cid}): text cell requires string 'value'.")
                        elif ctype == "button":
                            buttons = cell.get("buttons")
                            if not isinstance(buttons, list) or len(buttons) < 1:
                                errs.append(f"{p}.items.row[{ri}] ({cid}): button cell requires 'buttons' array.")
                            else:
                                for bi, b in enumerate(buttons):
                                    _validate_table_button(b, f"{p}.items.row[{ri}] ({cid}).buttons[{bi}]")
                        elif ctype == "dropdown":
                            value_ok = isinstance(cell.get("value"), str)
                            options = _extract_dropdown_options(cell.get("items"))
                            col_options = _extract_dropdown_options(col.get("items"))
                            if not value_ok and len(options) < 1 and len(col_options) < 1:
                                errs.append(
                                    f"{p}.items.row[{ri}] ({cid}): dropdown cell requires 'value' "
                                    "or non-empty 'items' array."
                                )

                    missing = sorted(set(col_ids) - set(seen_cols))
                    extra = sorted(set(seen_cols) - set(col_ids))
                    if missing:
                        errs.append(f"{p}.items.row: missing entries for columns {missing}.")
                    if extra:
                        errs.append(f"{p}.items.row: unknown column references {extra}.")
        ch = e.get("ch")
        if ch is not None and not isinstance(ch, list):
            errs.append(f"{p}: ch must be array.")
        if isinstance(ch, list):
            for i, c in enumerate(ch):
                if isinstance(c, dict):
                    check_e(c, f"{p}.ch[{i}]")
                else:
                    errs.append(f"{p}.ch[{i}] must be object.")

    for group in ("screens", "modals", "dialogs"):
        for c in dsl.get(group, []):
            for i, e in enumerate(c.get("elements", [])):
                if isinstance(e, dict):
                    check_e(e, f"{group}[{c.get('id')}].elements[{i}]")
                else:
                    errs.append(f"{group}[{c.get('id')}].elements[{i}] must be object.")
    if errs:
        raise DSLValidationError("\n".join(errs))


class Compiler:
    SW, SH, SG, SI = 1500, 900, 300, 48
    MODAL_W, DIALOG_W = 800, 520
    OI = 24
    OVERLAY_BASE_Y = SH + 200
    OVERLAY_GAP_Y = 120
    OVERLAY_COL_GAP = 120
    MODAL_X_OFFSET = 110

    def __init__(self, dsl: Dict[str, Any]) -> None:
        self.dsl = dsl
        self.ex = Excal()
        self.screen_idx: Dict[str, int] = {}

    def _style(self, token: str, role: str = "surface") -> Dict[str, str]:
        tone = SEMANTIC_TONES.get(token, SEMANTIC_TONES["neutral"])
        if role == "action":
            if token == "secondary":
                return {"stroke": tone["line"], "fill": TOKENS["white"], "text": tone["onSoft"], "border": 2}
            return {"stroke": tone["strong"], "fill": tone["strong"], "text": tone["onStrong"], "border": 1}
        if role == "status":
            return {"stroke": tone["strong"], "fill": tone["strong"], "text": tone["onStrong"], "border": 1}
        if role == "field":
            return {"stroke": TOKENS["gray300"], "fill": TOKENS["white"], "text": TOKENS["gray700"], "border": 1}
        if role == "nav":
            if token in {"primary", "secondary", "neutral", "background", "surface"}:
                return {"stroke": TOKENS["blue500"], "fill": TOKENS["blue500"], "text": TOKENS["white"], "border": 1}
            return {"stroke": tone["strong"], "fill": tone["strong"], "text": tone["onStrong"], "border": 1}
        if role == "panel":
            return {"stroke": tone["line"], "fill": tone["soft"], "text": tone["onSoft"], "border": 1}
        if role == "text":
            return {"stroke": tone["onSoft"], "fill": "transparent", "text": tone["onSoft"], "border": 0}
        if token in {"primary", "background"}:
            return {"stroke": TOKENS["blue300"], "fill": TOKENS["blue100"], "text": TOKENS["blue900"], "border": 1}
        return {"stroke": tone["line"], "fill": tone["soft"], "text": tone["onSoft"], "border": 1}

    def _tcolor(self, tc: Optional[str], fb: str) -> str:
        return TEXT_HEX.get(tc, fb) if tc else fb

    def _label(self, e: Dict[str, Any]) -> str:
        for k in ("txt", "label", "placeholder"):
            v = e.get(k)
            if isinstance(v, str) and v.strip():
                return v.strip()
        return ""

    def _target(self, e: Dict[str, Any]) -> Optional[str]:
        act = e.get("act")
        if isinstance(act, dict) and act.get("type") == "navigate" and isinstance(act.get("target"), str):
            return act["target"]
        return None

    def _link(self, e: Dict[str, Any]) -> Optional[str]:
        # Excalidraw renders a visible link badge; keep links hidden in UI output.
        return None

    def _hint(self, t: Optional[str], x: float, y: float, w: float) -> None:
        if not t:
            return
        tw, _, _ = self.ex._txt_size(t, 11)
        ty = y - 16 if y >= 18 else y + 2
        self.ex.text(t, x + max(0.0, (w - tw) / 2.0), ty, TOKENS["blue700"], fs=11)

    def _center_text(self, text: str, x: float, y: float, w: float, h: float, color: str, fs: int = 14, link: Optional[str] = None) -> None:
        tw, th, _ = self.ex._txt_size(text, fs)
        self.ex.text(text, x + max(0.0, (w - tw) / 2.0), y + max(0.0, (h - th) / 2.0), color, fs=fs, link=link)

    def _fit_text_fs(self, text: str, box_w: float, box_h: float, *, preferred: int = 14, min_fs: int = 11, max_fs: int = 16) -> int:
        fs = max(min_fs, min(max_fs, min(preferred, int(max(min_fs, box_h * 0.45)))))
        while fs > min_fs:
            tw, th, _ = self.ex._txt_size(text, fs)
            if tw <= box_w and th <= box_h:
                break
            fs -= 1
        return fs

    def _frame_screen(self, cid: str, name: str, g: Geo) -> None:
        self.ex.text(f"{cid} - {name}", g.fx, g.fy - 26, TOKENS["blue800"], fs=14)
        self.ex.rect(g.fx, g.fy, g.fw, g.fh, TOKENS["blue700"], TOKENS["white"], sw=2, rounded=True)

    def _frame_modal(self, cid: str, name: str, parent: str, g: Geo) -> None:
        self.ex.text(f"{cid} - {name} (Modal of {parent})", g.fx, g.fy - 24, TOKENS["blue800"], fs=12)
        self.ex.rect(g.fx, g.fy, g.fw, g.fh, TOKENS["blue300"], TOKENS["white"], sw=1, rounded=True)
        self.ex.text(name, g.fx + 24, g.fy + 24, TOKENS["blue800"], fs=24)
        self.ex.rect(g.fx + 24, g.fy + 64, g.fw - 48, 1, TOKENS["blue300"], TOKENS["blue300"], rounded=False)

    def _frame_dialog(self, cid: str, name: str, parent: str, g: Geo) -> None:
        self.ex.text(f"{cid} - {name} (Dialog of {parent})", g.fx, g.fy - 24, TOKENS["blue800"], fs=12)
        self.ex.rect(g.fx, g.fy, g.fw, g.fh, TOKENS["gray300"], TOKENS["white"], sw=1, rounded=True)
        self.ex.text(name, g.fx + 20, g.fy + 18, TOKENS["blue800"], fs=20)
        self.ex.rect(g.fx + 20, g.fy + 52, g.fw - 40, 1, TOKENS["blue300"], TOKENS["blue300"], rounded=False)

    def _dialog_options(self, elements: List[Dict[str, Any]]) -> List[Tuple[str, Optional[str]]]:
        options: List[Tuple[str, Optional[str]]] = []

        def walk(node: Dict[str, Any]) -> None:
            label = self._label(node)
            target = self._target(node)
            if label:
                options.append((label, target))
            for ch in node.get("ch", []) if isinstance(node.get("ch"), list) else []:
                if isinstance(ch, dict):
                    walk(ch)

        for item in elements:
            if isinstance(item, dict):
                walk(item)
        return options

    def _render_dialog_options(self, cid: str, name: str, parent: str, g: Geo, options: List[Tuple[str, Optional[str]]]) -> None:
        self.ex.text(f"{cid} - {name} (Dialog of {parent})", g.fx, g.fy - 24, TOKENS["blue800"], fs=12)
        self.ex.rect(g.fx, g.fy, g.fw, g.fh, TOKENS["blue700"], TOKENS["white"], sw=1, rounded=True)
        if not options:
            self._center_text(name, g.fx, g.fy, g.fw, g.fh, TOKENS["blue800"], fs=16)
            return
        row_h = g.fh / max(1, len(options))
        for idx, (label, target) in enumerate(options):
            ry = g.fy + idx * row_h
            fill = TOKENS["blue200"] if idx == 0 else TOKENS["white"]
            self.ex.rect(g.fx, ry, g.fw, row_h, TOKENS["blue300"], fill, rounded=False)
            self.ex.text(label, g.fx + 16, ry + max(8.0, (row_h - 16) / 2.0), TOKENS["black"], fs=14)
            self._hint(target, g.fx, ry, g.fw)

    def _screen_geo(self, idx: int) -> Geo:
        fx = idx * (self.SW + self.SG)
        return Geo(fx, 0, self.SW, self.SH, self.SI, self.SI, self.SW - 2 * self.SI, self.SH - 2 * self.SI)

    def _overlay_geo(self, fx: float, fy: float, fw: float, fh: float, header_h: float) -> Geo:
        return Geo(fx, fy, fw, fh, self.OI, header_h, fw - 2 * self.OI, max(1.0, fh - header_h - self.OI))

    @staticmethod
    def _max_extent(elements: List[Dict[str, Any]]) -> int:
        max_h = 0

        def walk(node: Dict[str, Any]) -> None:
            nonlocal max_h
            try:
                max_h = max(max_h, int(node.get("y", 0)) + int(node.get("h", 0)))
            except Exception:
                pass
            for ch in node.get("ch", []) if isinstance(node.get("ch"), list) else []:
                if isinstance(ch, dict):
                    walk(ch)

        for item in elements:
            if isinstance(item, dict):
                walk(item)
        return max_h

    @staticmethod
    def _estimate_overlay_h(extent: int, *, is_modal: bool) -> int:
        if is_modal:
            return int(max(420, min(700, 220 + extent * 0.5)))
        return int(max(320, min(520, 170 + extent * 0.35)))

    def compile(self) -> Dict[str, Any]:
        for i, s in enumerate(self.dsl.get("screens", [])):
            sid = s["id"]
            self.screen_idx[sid] = i
            g = self._screen_geo(i)
            self._frame_screen(sid, s.get("name", sid), g)
            for e in s.get("elements", []):
                self._render_element(e, g)

        modal_cursor_y: Dict[str, float] = {}
        dialog_cursor_y: Dict[str, float] = {}

        for i, m in enumerate(self.dsl.get("modals", [])):
            p = m["parentScreen"]
            sidx = self.screen_idx.get(p, i)
            sx = sidx * (self.SW + self.SG)
            x = sx + self.MODAL_X_OFFSET
            y = modal_cursor_y.get(p, self.OVERLAY_BASE_Y)
            oh = self._estimate_overlay_h(self._max_extent(m.get("elements", [])), is_modal=True)
            g = self._overlay_geo(x, y, self.MODAL_W, oh, header_h=84)
            self._frame_modal(m["id"], m.get("name", m["id"]), p, g)
            for e in m.get("elements", []):
                self._render_element(e, g)
            modal_cursor_y[p] = y + oh + self.OVERLAY_GAP_Y

        for i, d in enumerate(self.dsl.get("dialogs", [])):
            p = d["parentScreen"]
            sidx = self.screen_idx.get(p, i)
            sx = sidx * (self.SW + self.SG)
            x = sx + self.MODAL_X_OFFSET + self.MODAL_W + self.OVERLAY_COL_GAP
            y = dialog_cursor_y.get(p, self.OVERLAY_BASE_Y)
            options = self._dialog_options(d.get("elements", []))
            oh = max(88, min(620, max(1, len(options)) * 44))
            g = self._overlay_geo(x, y, self.DIALOG_W, oh, header_h=0)
            self._render_dialog_options(d["id"], d.get("name", d["id"]), p, g, options)
            dialog_cursor_y[p] = y + oh + self.OVERLAY_GAP_Y
        return self.ex.out()

    def _extract_table_columns_and_row(self, items: Dict[str, Any]) -> Tuple[List[Dict[str, Any]], Dict[str, Dict[str, Any]]]:
        cols = items.get("columns") if isinstance(items.get("columns"), list) else []
        row_entries = items.get("row") if isinstance(items.get("row"), list) else []
        row_map: Dict[str, Dict[str, Any]] = {}
        for entry in row_entries:
            if not isinstance(entry, dict):
                continue
            col = entry.get("column")
            if isinstance(col, str) and col.strip():
                row_map[col] = entry
        return [c for c in cols if isinstance(c, dict)], row_map

    @staticmethod
    def _row_text_value(cell: Dict[str, Any]) -> str:
        value = cell.get("value")
        return value if isinstance(value, str) else ""

    @staticmethod
    def _row_buttons_value(cell: Dict[str, Any], col: Dict[str, Any]) -> List[Dict[str, Any]]:
        if isinstance(cell.get("buttons"), list):
            return [b for b in cell["buttons"] if isinstance(b, dict)]
        if isinstance(col.get("buttons"), list):
            return [b for b in col["buttons"] if isinstance(b, dict)]
        return []

    @staticmethod
    def _row_dropdown_options(cell: Dict[str, Any], col: Dict[str, Any]) -> List[str]:
        options = _extract_dropdown_options(cell.get("items"))
        if options:
            return options
        return _extract_dropdown_options(col.get("items"))

    @staticmethod
    def _row_dropdown_value(cell: Dict[str, Any], col: Dict[str, Any]) -> str:
        value = cell.get("value")
        if isinstance(value, str) and value.strip():
            return value.strip()
        options = Compiler._row_dropdown_options(cell, col)
        return options[0] if options else ""

    def _render_table(self, e: Dict[str, Any], x: float, y: float, w: float, h: float, target: Optional[str]) -> None:
        items = e.get("items") if isinstance(e.get("items"), dict) else {}
        cols, row_map = self._extract_table_columns_and_row(items) if isinstance(items, dict) else ([], {})
        rows: List[Dict[str, Dict[str, Any]]] = [row_map] if cols and row_map else []

        pagination_h = max(56.0, min(76.0, h * 0.22))
        table_h = max(120.0, h - pagination_h - 10.0)
        header_h = 46.0
        row_count = len(rows)
        body_h = max(1.0, table_h - header_h)
        row_h = min(56.0, body_h) if row_count <= 1 else body_h / row_count

        self.ex.rect(x, y, w, table_h, TOKENS["blue300"], TOKENS["white"], sw=1, rounded=True)
        self.ex.rect(x, y, w, header_h, TOKENS["blue300"], TOKENS["blue200"], rounded=False)

        if not cols:
            self._center_text("Table", x, y, w, table_h, TOKENS["blue800"])
            self._hint(target, x, y, w)
            return

        weights: List[float] = []
        for col in cols:
            col_type = str(col.get("type", "text"))
            weights.append(1.4 if col_type == "button" else 1.0)
        total = sum(weights) if sum(weights) > 0 else float(len(cols))
        widths = [w * (wt / total) for wt in weights]
        starts: List[float] = []
        run = x
        for cw in widths:
            starts.append(run)
            run += cw

        for idx, col in enumerate(cols):
            cx, cw = starts[idx], widths[idx]
            title = str(col.get("label") or col.get("id") or f"Column {idx + 1}")
            self.ex.text(title, cx + 12, y + 14, TOKENS["blue800"], fs=14)

        for r_idx, row in enumerate(rows):
            ry = y + header_h + r_idx * row_h
            fill = TOKENS["white"] if r_idx % 2 == 0 else TOKENS["blue100"]
            self.ex.rect(x, ry, w, row_h, TOKENS["blue300"], fill, rounded=False)
            if r_idx > 0:
                self.ex.rect(x, ry, w, 1, TOKENS["blue300"], TOKENS["blue300"], rounded=False)

            for c_idx, col in enumerate(cols):
                cx, cw = starts[c_idx], widths[c_idx]
                ctype = str(col.get("type", "text"))
                cid = str(col.get("id", ""))
                cell = row.get(cid, {})
                cy = ry + max(10.0, (row_h - 16.0) / 2.0)

                if ctype == "button":
                    btns = self._row_buttons_value(cell, col)
                    if not btns:
                        continue
                    gap = 8.0
                    bw = max(72.0, min(140.0, (cw - 24.0 - gap * (len(btns) - 1)) / max(1, len(btns))))
                    bh = min(32.0, max(24.0, row_h - 12.0))
                    by = ry + (row_h - bh) / 2.0
                    for b_idx, button in enumerate(btns):
                        bx = cx + 12 + b_idx * (bw + gap)
                        bstyle = self._style(str(button.get("c", col.get("c", "secondary"))), role="action")
                        border_w = int(bstyle.get("border", 1))
                        self.ex.rect(bx, by, bw, bh, bstyle["stroke"], bstyle["fill"], sw=border_w, link=None)
                        btxt = str(button.get("txt") or "")
                        if btxt:
                            self._center_text(btxt, bx, by, bw, bh, bstyle["text"], fs=14, link=None)
                        btarget = button.get("act", {}).get("target") if isinstance(button.get("act"), dict) else None
                        self._hint(btarget if isinstance(btarget, str) else None, bx, by, bw)
                    continue

                if ctype == "dropdown":
                    field_h = min(32.0, max(24.0, row_h - 12.0))
                    field_y = ry + (row_h - field_h) / 2.0
                    field_x = cx + 12.0
                    field_w = max(72.0, cw - 24.0)
                    self.ex.rect(field_x, field_y, field_w, field_h, TOKENS["gray300"], TOKENS["white"], sw=1, rounded=False)
                    dvalue = self._row_dropdown_value(cell, col)
                    if dvalue:
                        fs = self._fit_text_fs(dvalue, field_w - 26.0, field_h - 8.0, preferred=13, min_fs=11, max_fs=14)
                        self.ex.text(dvalue, field_x + 8.0, field_y + max(6.0, (field_h - 14.0) / 2.0), TOKENS["gray700"], fs=fs)
                    self.ex.text("v", field_x + field_w - 14.0, field_y + max(6.0, (field_h - 14.0) / 2.0), TOKENS["blue800"], fs=12)
                    continue

                text_value = self._row_text_value(cell)
                if text_value:
                    fs = self._fit_text_fs(text_value, cw - 24.0, row_h - 10.0, preferred=14, min_fs=11, max_fs=14)
                    self.ex.text(text_value, cx + 12, cy, TOKENS["black"], fs=fs)

        py = y + table_h + 8
        total_rows = len(rows)
        page_size = min(4, total_rows) if total_rows > 0 else 0
        from_idx = 1 if total_rows > 0 else 0
        self.ex.text(f"{from_idx} de {page_size} dos {total_rows} resultados", x + 12, py + 16, TOKENS["black"], fs=14)
        btn = 44.0
        gap = 12.0
        pages = max(1, math.ceil(total_rows / max(1, page_size if page_size > 0 else 1)))
        nx = x + w - (btn * 4 + gap * 3) - 12.0
        prev_next = self._style("secondary", role="action")
        current = self._style("primary", role="action")
        page_btn = self._style("secondary", role="action")
        self.ex.rect(nx, py + 2, btn, btn, prev_next["stroke"], prev_next["fill"], sw=int(prev_next.get("border", 1)))
        self._center_text("<", nx, py + 2, btn, btn, prev_next["text"], fs=16)
        self.ex.rect(nx + (btn + gap), py + 2, btn, btn, current["stroke"], current["fill"], sw=int(current.get("border", 1)))
        self._center_text("1", nx + (btn + gap), py + 2, btn, btn, current["text"], fs=14)
        self.ex.rect(nx + (btn + gap) * 2, py + 2, btn, btn, page_btn["stroke"], page_btn["fill"], sw=int(page_btn.get("border", 1)))
        self._center_text("2" if pages >= 2 else "1", nx + (btn + gap) * 2, py + 2, btn, btn, page_btn["text"], fs=14)
        self.ex.rect(nx + (btn + gap) * 3, py + 2, btn, btn, prev_next["stroke"], prev_next["fill"], sw=int(prev_next.get("border", 1)))
        self._center_text(">", nx + (btn + gap) * 3, py + 2, btn, btn, prev_next["text"], fs=16)
        self._hint(target, x, y, w)

    def _render_element(self, e: Dict[str, Any], g: Geo) -> None:
        t = e.get("t")
        x, y, w, h = int(e.get("x", 0)), int(e.get("y", 0)), int(e.get("w", 1)), int(e.get("h", 1))
        gx, gy, gw, gh = g.p(x, y, w, h)
        token = str(e.get("c", "neutral"))
        s = self._style(token, role="surface")
        lbl = self._label(e)
        link = self._link(e)
        target = self._target(e)

        if t == "text":
            if lbl:
                fs = self._fit_text_fs(lbl, gw, gh, preferred=14, min_fs=11, max_fs=16)
                txt_style = self._style(token, role="text")
                self.ex.text(lbl, gx, gy, self._tcolor(e.get("tc"), txt_style["text"]), fs=fs, link=link)
            self._hint(target, gx, gy, gw)
        elif t == "radio":
            field = self._style(token, role="field")
            size = min(gw, gh, 18.0)
            cy = gy + max(0.0, (gh - size) / 2)
            self.ex.ellipse(gx, cy, size, size, field["stroke"], TOKENS["white"], sw=2, link=link)
            if lbl:
                self.ex.text(lbl, gx + size + 8, gy + max(0.0, (gh - 14) / 2), self._style(token, role="text")["text"], link=link)
            self._hint(target, gx, gy, gw)
        elif t == "checkbox":
            field = self._style(token, role="field")
            size = min(gw, gh, 18.0)
            cy = gy + max(0.0, (gh - size) / 2)
            self.ex.rect(gx, cy, size, size, field["stroke"], TOKENS["white"], sw=2, rounded=False, link=link)
            if lbl:
                self.ex.text(lbl, gx + size + 8, gy + max(0.0, (gh - 14) / 2), self._style(token, role="text")["text"], link=link)
            self._hint(target, gx, gy, gw)
        elif t == "divider":
            dh = max(1.0, min(gh, 2.0))
            self.ex.rect(gx, gy + (gh - dh) / 2, gw, dh, TOKENS["blue300"], TOKENS["blue300"], rounded=False, link=link)
            self._hint(target, gx, gy, gw)
        elif t == "table":
            self._render_table(e, gx, gy, gw, gh, target)
        elif t == "icon":
            icon_style = self._style(token, role="status")
            size = min(gw, gh)
            self.ex.ellipse(gx, gy, size, size, icon_style["stroke"], icon_style["fill"], link=link)
            if lbl:
                self._center_text(lbl[:2].upper(), gx, gy, size, size, icon_style["text"], fs=12, link=link)
            self._hint(target, gx, gy, gw)
        elif t == "button":
            btn = self._style(token, role="action")
            self.ex.rect(gx, gy, gw, gh, btn["stroke"], btn["fill"], sw=int(btn.get("border", 1)), link=link)
            self._center_text(lbl, gx, gy, gw, gh, btn["text"], fs=max(12, min(16, int(gh * 0.45))), link=link)
            self._hint(target, gx, gy, gw)
        elif t in {"badge", "alert"}:
            status = self._style(token, role="status")
            self.ex.rect(gx, gy, gw, gh, status["stroke"], status["fill"], sw=int(status.get("border", 1)), link=link)
            self._center_text(lbl, gx, gy, gw, gh, status["text"], fs=max(12, min(16, int(gh * 0.45))), link=link)
            self._hint(target, gx, gy, gw)
        elif t in {"input", "textarea", "dropdown", "search"}:
            field = self._style(token, role="field")
            self.ex.rect(gx, gy, gw, gh, field["stroke"], field["fill"], link=link)
            ph = str(e.get("placeholder") or e.get("txt") or e.get("label") or "")
            if ph:
                self.ex.text(ph, gx + 12, gy + max(6.0, (gh - 14) / 2), field["text"], link=link)
            if t == "dropdown":
                self.ex.text("v", gx + gw - 18, gy + max(6.0, (gh - 14) / 2), TOKENS["blue800"], link=link)
            if t == "search":
                si = min(gh - 12.0, 12.0)
                self.ex.ellipse(gx + 8, gy + (gh - si) / 2, si, si, TOKENS["blue800"], "transparent", link=link)
            self._hint(target, gx, gy, gw)
        elif t == "list":
            panel = self._style(token, role="panel")
            self.ex.rect(gx, gy, gw, gh, panel["stroke"], TOKENS["white"], link=link)
            title_h = min(44.0, gh * 0.26)
            self.ex.rect(gx, gy, gw, title_h, panel["stroke"], TOKENS["blue100"], rounded=False, link=link)
            self.ex.text(lbl or "List", gx + 12, gy + 12, panel["text"], fs=14, link=link)
            self.ex.text("Lorem ipsum dolor sit amet consectetur.", gx + 12, gy + title_h + 14, TOKENS["black"], fs=14, link=link)
            self._hint(target, gx, gy, gw)
        elif t == "tabs":
            tab_surface = self._style(token, role="panel")
            self.ex.rect(gx, gy, gw, gh, tab_surface["stroke"], TOKENS["white"], link=link)
            tw = gw / 3.0
            for i in range(3):
                tx = gx + i * tw
                fill = TOKENS["white"] if i == 0 else TOKENS["blue100"]
                self.ex.rect(tx, gy, tw, gh, tab_surface["stroke"], fill, rounded=False, link=link)
                if i == 0:
                    self.ex.rect(tx, gy + gh - 2, tw, 2, TOKENS["blue900"], TOKENS["blue900"], rounded=False, link=link)
                self._center_text(f"Tab {i+1}", tx, gy, tw, gh, TOKENS["blue800"], fs=12, link=link)
            self._hint(target, gx, gy, gw)
        elif t == "image":
            self.ex.rect(gx, gy, gw, gh, TOKENS["blue300"], TOKENS["white"], link=link)
            self._center_text("Image", gx, gy, gw, gh, TOKENS["gray700"], link=link)
            self._hint(target, gx, gy, gw)
        elif t in {"navbar", "header", "footer"}:
            nav = self._style(token, role="nav")
            self.ex.rect(gx, gy, gw, gh, nav["stroke"], nav["fill"], sw=int(nav.get("border", 1)), link=link)
            if lbl:
                self.ex.text(lbl, gx + 12, gy + max(8.0, (gh - 16) / 2.0), nav["text"], fs=14, link=link)
            self._hint(target, gx, gy, gw)
        elif t == "sidebar":
            panel = self._style(token, role="panel")
            self.ex.rect(gx, gy, gw, gh, panel["stroke"], panel["fill"], sw=int(panel.get("border", 1)), link=link)
            if lbl:
                self.ex.text(lbl, gx + 12, gy + 10, panel["text"], fs=max(12, min(16, int(gh * 0.45))), link=link)
            self._hint(target, gx, gy, gw)
        else:
            self.ex.rect(gx, gy, gw, gh, s["stroke"], s["fill"], link=link)
            if lbl:
                self.ex.text(lbl, gx + 12, gy + 10, s["text"], fs=max(12, min(16, int(gh * 0.45))), link=link)
            self._hint(target, gx, gy, gw)

        ch = e.get("ch")
        if isinstance(ch, list):
            for c in ch:
                if isinstance(c, dict):
                    self._render_element(c, g)


def compile_dsl_to_excalidraw(dsl: Dict[str, Any]) -> Dict[str, Any]:
    validate_dsl(dsl)
    return Compiler(dsl).compile()

# n8n wrapper: compile incoming DSL from item.json.designDsl
outputs = []
for item in _items:
    src = item.get("json", {}) if isinstance(item, dict) else {}
    out_json = dict(src)

    try:
        raw = src.get("designDsl")
        if raw is None:
            raise ValueError("Missing 'designDsl' in input json")

        if isinstance(raw, str):
            dsl_payload = json.loads(raw)
        elif isinstance(raw, dict):
            dsl_payload = raw
        else:
            raise ValueError("'designDsl' must be a JSON string or object")

        compiled = compile_dsl_to_excalidraw(dsl_payload)
        out_json["design"] = json.dumps(compiled, ensure_ascii=False)
        out_json["designElementCount"] = len(compiled.get("elements", []))
        out_json["designStopReason"] = "compiled-python"
        out_json.pop("designCompileError", None)
    except Exception as err:
        fallback = {
            "type": "excalidraw",
            "version": 2,
            "source": "https://excalidraw.com",
            "elements": [],
            "appState": {"viewBackgroundColor": "#F7F7F7", "gridSize": None},
            "files": {},
        }
        out_json["design"] = json.dumps(fallback, ensure_ascii=False)
        out_json["designElementCount"] = 0
        out_json["designStopReason"] = "compile-error"
        out_json["designCompileError"] = str(err)

    out_item = {"json": out_json}
    if isinstance(item, dict) and item.get("binary") is not None:
        out_item["binary"] = item.get("binary")

    outputs.append(out_item)

return outputs

import base64
import io
import json
import math
import zipfile
from PIL import Image, ImageColor, ImageDraw, ImageFont

SW, SH, SG = 1500, 900, 300
MODAL_W, DIALOG_W = 800, 520
OVERLAY_BASE_Y = SH + 200
OVERLAY_GAP_Y = 120
OVERLAY_COL_GAP = 120
MODAL_X_OFFSET = 110


def _to_number(value, default=0.0):
    try:
        return float(value)
    except Exception:
        return float(default)


def _label_from_node(node):
    for key in ("txt", "label", "placeholder"):
        value = node.get(key)
        if isinstance(value, str) and value.strip():
            return value.strip()
    return ""


def _max_extent(elements):
    max_h = 0

    def walk(node):
        nonlocal max_h
        try:
            y = int(node.get("y", 0))
            h = int(node.get("h", 0))
            max_h = max(max_h, y + h)
        except Exception:
            pass
        children = node.get("ch")
        if isinstance(children, list):
            for child in children:
                if isinstance(child, dict):
                    walk(child)

    if isinstance(elements, list):
        for element in elements:
            if isinstance(element, dict):
                walk(element)
    return max_h


def _estimate_overlay_h(extent, is_modal):
    if is_modal:
        return int(max(420, min(700, 220 + extent * 0.5)))
    return int(max(320, min(520, 170 + extent * 0.35)))


def _dialog_option_count(elements):
    count = 0

    def walk(node):
        nonlocal count
        if _label_from_node(node):
            count += 1
        children = node.get("ch")
        if isinstance(children, list):
            for child in children:
                if isinstance(child, dict):
                    walk(child)

    if isinstance(elements, list):
        for element in elements:
            if isinstance(element, dict):
                walk(element)
    return count


def _compute_frames(dsl):
    frames = []
    screens = dsl.get("screens") if isinstance(dsl, dict) else []
    modals = dsl.get("modals") if isinstance(dsl, dict) else []
    dialogs = dsl.get("dialogs") if isinstance(dsl, dict) else []

    screens = screens if isinstance(screens, list) else []
    modals = modals if isinstance(modals, list) else []
    dialogs = dialogs if isinstance(dialogs, list) else []

    screen_idx = {}
    for index, screen in enumerate(screens):
        if not isinstance(screen, dict):
            continue
        sid = str(screen.get("id") or f"S{index+1}")
        sname = str(screen.get("name") or sid)
        fx = index * (SW + SG)
        screen_idx[sid] = index
        frames.append(
            {
                "id": sid,
                "name": sname,
                "type": "screen",
                "x": fx,
                "y": 0,
                "w": SW,
                "h": SH,
            }
        )

    modal_cursor_y = {}
    for index, modal in enumerate(modals):
        if not isinstance(modal, dict):
            continue
        mid = str(modal.get("id") or f"M{index+1}")
        mname = str(modal.get("name") or mid)
        parent = str(modal.get("parentScreen") or "")
        sidx = screen_idx.get(parent, index)
        sx = sidx * (SW + SG)
        x = sx + MODAL_X_OFFSET
        y = float(modal_cursor_y.get(parent, OVERLAY_BASE_Y))
        oh = _estimate_overlay_h(_max_extent(modal.get("elements")), True)
        frames.append(
            {
                "id": mid,
                "name": mname,
                "type": "modal",
                "parentScreen": parent,
                "x": x,
                "y": y,
                "w": MODAL_W,
                "h": oh,
            }
        )
        modal_cursor_y[parent] = y + oh + OVERLAY_GAP_Y

    dialog_cursor_y = {}
    for index, dialog in enumerate(dialogs):
        if not isinstance(dialog, dict):
            continue
        did = str(dialog.get("id") or f"D{index+1}")
        dname = str(dialog.get("name") or did)
        parent = str(dialog.get("parentScreen") or "")
        sidx = screen_idx.get(parent, index)
        sx = sidx * (SW + SG)
        x = sx + MODAL_X_OFFSET + MODAL_W + OVERLAY_COL_GAP
        y = float(dialog_cursor_y.get(parent, OVERLAY_BASE_Y))
        options_count = _dialog_option_count(dialog.get("elements"))
        oh = max(88, min(620, max(1, options_count) * 44))
        frames.append(
            {
                "id": did,
                "name": dname,
                "type": "dialog",
                "parentScreen": parent,
                "x": x,
                "y": y,
                "w": DIALOG_W,
                "h": oh,
            }
        )
        dialog_cursor_y[parent] = y + oh + OVERLAY_GAP_Y

    return frames


def _element_bounds(element):
    x = _to_number(element.get("x"), 0)
    y = _to_number(element.get("y"), 0)
    w = _to_number(element.get("width"), _to_number(element.get("w"), 0))
    h = _to_number(element.get("height"), _to_number(element.get("h"), 0))
    if w < 0:
        w = 0
    if h < 0:
        h = 0
    return {"x": x, "y": y, "w": w, "h": h}


def _intersects(a, b):
    return not (
        a["x"] + a["w"] < b["x"]
        or a["x"] > b["x"] + b["w"]
        or a["y"] + a["h"] < b["y"]
        or a["y"] > b["y"] + b["h"]
    )


def _elements_overall_bbox(elements):
    xs = []
    ys = []
    x2 = []
    y2 = []
    if not isinstance(elements, list):
        return None
    for element in elements:
        if not isinstance(element, dict) or element.get("isDeleted"):
            continue
        b = _element_bounds(element)
        xs.append(b["x"])
        ys.append(b["y"])
        x2.append(b["x"] + b["w"])
        y2.append(b["y"] + b["h"])
    if not xs:
        return None
    return {"x": min(xs), "y": min(ys), "w": max(x2) - min(xs), "h": max(y2) - min(ys)}


def _overview_bbox(frames, elements):
    if frames:
        min_x = min(float(frame["x"]) for frame in frames)
        min_y = min(float(frame["y"]) for frame in frames) - 36
        max_x = max(float(frame["x"]) + float(frame["w"]) for frame in frames)
        max_y = max(float(frame["y"]) + float(frame["h"]) for frame in frames) + 24
        return {"x": min_x, "y": min_y, "w": max_x - min_x, "h": max_y - min_y}
    bbox = _elements_overall_bbox(elements)
    if bbox:
        return bbox
    return {"x": 0.0, "y": 0.0, "w": 1200.0, "h": 800.0}


def _color_to_rgba(value, alpha=255, fallback="#000000"):
    color = str(value or fallback).strip()
    if color.lower() in ("", "none", "transparent"):
        return (0, 0, 0, 0)
    try:
        rgb = ImageColor.getrgb(color)
        if len(rgb) == 4:
            return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))
        return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))
    except Exception:
        rgb = ImageColor.getrgb(fallback)
        return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))


def _pick_font(size):
    size = max(8, int(size))
    for path in (
        "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/TTF/DejaVuSans.ttf",
    ):
        try:
            return ImageFont.truetype(path, size=size)
        except Exception:
            continue
    return ImageFont.load_default()


def _render_png(elements, bbox, padding):
    px = float(bbox["x"]) - float(padding)
    py = float(bbox["y"]) - float(padding)
    pw = max(1.0, float(bbox["w"]) + 2.0 * float(padding))
    ph = max(1.0, float(bbox["h"]) + 2.0 * float(padding))
    width = int(math.ceil(pw))
    height = int(math.ceil(ph))

    ox = -px
    oy = -py

    img = Image.new("RGBA", (width, height), _color_to_rgba("#F7F7F7"))
    draw = ImageDraw.Draw(img, "RGBA")

    if isinstance(elements, list):
        for element in elements:
            if not isinstance(element, dict) or element.get("isDeleted"):
                continue

            etype = str(element.get("type") or "")
            x = _to_number(element.get("x"), 0) + ox
            y = _to_number(element.get("y"), 0) + oy
            w = max(0.0, _to_number(element.get("width"), 0))
            h = max(0.0, _to_number(element.get("height"), 0))
            stroke_w = max(1, int(round(_to_number(element.get("strokeWidth"), 1))))
            opacity = max(0.0, min(1.0, _to_number(element.get("opacity"), 100) / 100.0))
            alpha = int(255 * opacity)

            stroke = _color_to_rgba(element.get("strokeColor"), alpha=alpha, fallback="#000000")
            fill = _color_to_rgba(element.get("backgroundColor"), alpha=alpha, fallback="#FFFFFF")
            if str(element.get("backgroundColor") or "").lower() in ("", "none", "transparent"):
                fill = (0, 0, 0, 0)

            if etype == "rectangle":
                x2 = x + w
                y2 = y + h
                radius = 8 if element.get("roundness") else 0
                if radius > 0:
                    draw.rounded_rectangle((x, y, x2, y2), radius=radius, fill=fill, outline=stroke, width=stroke_w)
                else:
                    draw.rectangle((x, y, x2, y2), fill=fill, outline=stroke, width=stroke_w)
            elif etype == "ellipse":
                x2 = x + w
                y2 = y + h
                draw.ellipse((x, y, x2, y2), fill=fill, outline=stroke, width=stroke_w)
            elif etype == "text":
                text_value = str(element.get("text") or "")
                if not text_value:
                    continue
                fs = max(8, int(_to_number(element.get("fontSize"), 14)))
                font = _pick_font(fs)
                line_height = int(fs * 1.25)
                for idx, line in enumerate(text_value.splitlines() or [""]):
                    draw.text((x, y + idx * line_height), line, fill=stroke, font=font)

    out = io.BytesIO()
    img.save(out, format="PNG")
    return out.getvalue()


def _frame_asset_path(frame):
    ftype = str(frame.get("type") or "screen")
    folder = "screens"
    if ftype == "modal":
        folder = "modals"
    elif ftype == "dialog":
        folder = "dialogs"
    return f"{folder}/{frame.get('id', 'item')}.png"


outputs = []
for item in _items:
    src = item.get("json", {}) if isinstance(item, dict) else {}
    bin_in = item.get("binary", {}) if isinstance(item, dict) and isinstance(item.get("binary"), dict) else {}
    out_json = dict(src)
    out_binary = dict(bin_in)

    try:
        raw_design = src.get("design")
        raw_dsl = src.get("designDsl")

        if isinstance(raw_design, str):
            design = json.loads(raw_design)
        elif isinstance(raw_design, dict):
            design = raw_design
        else:
            design = {"elements": []}

        if isinstance(raw_dsl, str):
            dsl = json.loads(raw_dsl)
        elif isinstance(raw_dsl, dict):
            dsl = raw_dsl
        else:
            dsl = {"screens": [], "modals": [], "dialogs": []}

        elements = design.get("elements")
        if not isinstance(elements, list):
            elements = []

        frames = _compute_frames(dsl)
        overview = _overview_bbox(frames, elements)

        manifest_assets = []
        zip_buffer = io.BytesIO()
        with zipfile.ZipFile(zip_buffer, "w", zipfile.ZIP_DEFLATED) as zf:
            overview_png = _render_png(elements, overview, 32)
            zf.writestr("overview.png", overview_png)
            manifest_assets.append(
                {
                    "id": "overview",
                    "type": "overview",
                    "path": "overview.png",
                    "bbox": overview,
                    "elementCount": len(elements),
                }
            )

            for frame in frames:
                frame_box = {
                    "x": float(frame["x"]),
                    "y": float(frame["y"]) - 36.0,
                    "w": float(frame["w"]),
                    "h": float(frame["h"]) + 56.0,
                }
                subset = []
                for element in elements:
                    if isinstance(element, dict) and _intersects(_element_bounds(element), frame_box):
                        subset.append(element)

                path = _frame_asset_path(frame)
                png = _render_png(subset, frame_box, 16)
                zf.writestr(path, png)
                manifest_assets.append(
                    {
                        "id": frame.get("id"),
                        "name": frame.get("name"),
                        "type": frame.get("type"),
                        "path": path,
                        "bbox": frame_box,
                        "elementCount": len(subset),
                        "parentScreen": frame.get("parentScreen"),
                    }
                )

        manifest = {
            "counts": {
                "screens": sum(1 for f in frames if f.get("type") == "screen"),
                "modals": sum(1 for f in frames if f.get("type") == "modal"),
                "dialogs": sum(1 for f in frames if f.get("type") == "dialog"),
                "images": len(manifest_assets),
            },
            "assets": manifest_assets,
        }

        zip_bytes = zip_buffer.getvalue()
        revision = int(src.get("revisionNumber", 0) or 0)
        zip_name = f"design-assets-r{revision}.zip"

        out_binary["reviewZip"] = {
            "data": base64.b64encode(zip_bytes).decode("ascii"),
            "mimeType": "application/zip",
            "fileName": zip_name,
            "fileExtension": "zip",
            "fileSize": str(len(zip_bytes)),
        }
        out_json["designAssetCount"] = len(manifest_assets)
        out_json["designAssetManifest"] = manifest
        out_json["response"] = str(src.get("response") or f"Design assets ZIP generated: {manifest['counts']['images']} PNG images + source file.")
        out_json.pop("designAssetError", None)
    except Exception as err:
        out_json["designAssetCount"] = 0
        out_json["designAssetError"] = str(err)
        out_json["response"] = str(src.get("response") or "Failed to build design assets ZIP.")

    outputs.append({"json": out_json, "binary": out_binary})

return outputs

