const item = $input.first() ?? { json: {}, binary: {} };
const json = item?.json ?? {};

function getNodeItems(nodeName) {
  if (typeof $items !== 'function') return [];
  try {
    return $items(nodeName) || [];
  } catch (error) {
    const message = String(error?.message ?? error ?? '');
    if (message.includes("hasn't been executed") || message.includes('not executed')) {
      return [];
    }
    throw error;
  }
}

function splitLines(text) {
  return String(text ?? '').replace(/\r\n/g, '\n').split('\n');
}

function looksTextLike(binaryEntry, key) {
  const mime = String(binaryEntry?.mimeType ?? '').toLowerCase();
  const extRaw = String(binaryEntry?.fileExtension ?? '').toLowerCase();
  const ext = extRaw.startsWith('.') ? extRaw.slice(1) : extRaw;

  const textExt = new Set([
    'txt', 'md', 'markdown', 'json', 'yaml', 'yml', 'csv', 'tsv', 'xml', 'html', 'htm',
    'js', 'ts', 'py', 'java', 'c', 'cpp', 'cs', 'sql', 'log', 'ini', 'cfg',
  ]);

  if (mime.startsWith('text/')) return true;
  if (mime.includes('json') || mime.includes('xml') || mime.includes('yaml')) return true;
  if (textExt.has(ext)) return true;

  const keyLower = String(key ?? '').toLowerCase();
  if (keyLower.endsWith('.txt') || keyLower.endsWith('.md') || keyLower.endsWith('.json')) return true;

  return false;
}

function decodeText(binaryEntry) {
  try {
    const raw = String(binaryEntry?.data ?? '');
    if (!raw) return '';
    return Buffer.from(raw, 'base64').toString('utf8');
  } catch {
    return '';
  }
}

const hvItems = getNodeItems('DESIGN - Human Validation');
const hv1Items = getNodeItems('DESIGN - Human Validation1');
const loopItems = getNodeItems('DESIGN - Loop Decision');

const hvJson = hvItems[0]?.json ?? {};
const hv1Json = hv1Items[0]?.json ?? {};
const loopJson = loopItems[0]?.json ?? {};

const hvBinary = hvItems[0]?.binary ?? {};
const hv1Binary = hv1Items[0]?.binary ?? {};
const loopBinary = loopItems[0]?.binary ?? {};

const mergedJson = { ...hvJson, ...hv1Json, ...loopJson, ...json };
const mergedBinary = { ...hvBinary, ...hv1Binary, ...loopBinary, ...(item?.binary ?? {}) };

const designDsl = [
  mergedJson.designDsl,
  mergedJson.firstIterationDesignDsl,
  mergedJson.response,
]
  .map((value) => String(value ?? '').trim())
  .find((value) => value.length > 0) || '';

if (!designDsl) throw new Error('Design DSL draft is missing for refinement.');

let parsedDsl;
try {
  parsedDsl = JSON.parse(designDsl);
} catch (error) {
  throw new Error('Design DSL draft is not valid JSON: ' + error.message);
}

if (!parsedDsl || typeof parsedDsl !== 'object' || Array.isArray(parsedDsl)) {
  throw new Error('Design DSL draft must be a JSON object.');
}

const reviewerFeedback = [
  mergedJson.feedback,
  mergedJson.Feedback,
  loopJson.feedback,
  loopJson.Feedback,
  hv1Json.feedback,
  hv1Json.Feedback,
  hvJson.feedback,
  hvJson.Feedback,
]
  .map((value) => String(value ?? '').trim())
  .find((value) => value.length > 0)
  || 'Reviewer requested changes without additional details.';

const revisionNumber = Math.max(0, Math.trunc(Number(mergedJson.revisionNumber ?? 0) || 0)) + 1;

const attachmentEntries = Object.entries(mergedBinary)
  .filter(([key]) => /^attachments?(?:_|$)/i.test(String(key)));

const attachmentSummaries = [];
const attachmentTextBlocks = [];

let totalTextChars = 0;
const maxTotalChars = 24000;
const maxPerFileChars = 6000;

for (const [key, bin] of attachmentEntries) {
  const fileName = String(bin?.fileName ?? key);
  const mimeType = String(bin?.mimeType ?? 'application/octet-stream');
  const fileSize = Number(bin?.fileSize ?? 0);

  attachmentSummaries.push({ key, fileName, mimeType, fileSize });

  if (!looksTextLike(bin, key)) continue;
  if (totalTextChars >= maxTotalChars) continue;

  const text = decodeText(bin).trim();
  if (!text) continue;

  const remaining = maxTotalChars - totalTextChars;
  const take = Math.min(maxPerFileChars, remaining);
  const excerpt = text.slice(0, take);

  attachmentTextBlocks.push(`Attachment: ${fileName} (${mimeType})\n---\n${excerpt}`);
  totalTextChars += excerpt.length;
}

const attachmentSummaryText = attachmentSummaries.length
  ? attachmentSummaries.map((a, i) => `${i + 1}) ${a.fileName} | mime=${a.mimeType} | size=${a.fileSize}`).join('\n')
  : '[No attachments provided.]';

const attachmentExtractedText = attachmentTextBlocks.length
  ? attachmentTextBlocks.join('\n\n')
  : '[No text could be extracted from attachments automatically.]';

const patchPromptParts = [
  'You are correcting an existing UI Design DSL JSON draft.',
  'Use all available reviewer inputs below.',
  '',
  'Input priority (highest to lowest):',
  '1) Explicit reviewer feedback field',
  '2) Attachment context (metadata + extracted text when available)',
  '3) Current Design DSL draft',
  '',
  'MANDATORY ENFORCEMENT:',
  '- Apply all explicit reviewer requests when they are structurally compatible with the DSL schema.',
  '- Preserve valid screens/modals/dialogs and navigation links unless they conflict with reviewer requests.',
  '- Keep output as valid JSON with top-level keys: screens, modals, dialogs.',
  '- Keep IDs stable whenever possible.',
  '',
  'Return ONLY the FULL corrected DSL JSON object.',
  '- First character MUST be {',
  '- Do NOT return markdown fences.',
  '- Do NOT explain your answer.',
  '- Do NOT return diffs or patch instructions.',
  '',
  'Reviewer feedback:',
  reviewerFeedback,
  '',
  'Attachment metadata:',
  attachmentSummaryText,
  '',
  'Extracted attachment text (partial when available):',
  attachmentExtractedText,
  '',
  'Current Design DSL draft with line numbers:',
  splitLines(JSON.stringify(parsedDsl, null, 2)).map((line, idx) => `${idx + 1}: ${line}`).join('\n'),
];

return [{
  json: {
    designDsl: JSON.stringify(parsedDsl),
    reviewerFeedback,
    revisionNumber,
    attachmentCount: attachmentSummaries.length,
    attachmentSummaries,
    patchPrompt: patchPromptParts.join('\n'),
  },
  ...(mergedBinary && Object.keys(mergedBinary).length > 0 ? { binary: mergedBinary } : {}),
}];

function parseCandidate(raw) {
  try {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed;
    }
  } catch {}
  return null;
}

function normalizeText(raw) {
  let text = String(raw ?? '').trim();
  if (!text) {
    throw new Error('Design refinement model output is empty.');
  }

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    text = fenced[1].trim();
  }

  return text;
}

function validateDsl(payload) {
  const requiredKeys = ['screens', 'modals', 'dialogs'];
  for (const key of requiredKeys) {
    if (!(key in payload)) {
      throw new Error(`Design DSL is missing '${key}'.`);
    }
    if (!Array.isArray(payload[key])) {
      throw new Error(`Design DSL key '${key}' must be an array.`);
    }
  }
}

function extractDsl(rawText) {
  const text = normalizeText(rawText);
  const candidates = [];

  candidates.push(text);

  const firstObjectStart = text.indexOf('{');
  const lastObjectEnd = text.lastIndexOf('}');
  if (firstObjectStart >= 0 && lastObjectEnd > firstObjectStart) {
    candidates.push(text.slice(firstObjectStart, lastObjectEnd + 1));
  }

  for (const candidate of candidates) {
    const parsed = parseCandidate(candidate);
    if (!parsed) continue;

    validateDsl(parsed);
    return parsed;
  }

  throw new Error('Could not extract valid DSL JSON from design refinement output.');
}

const item = $input.first();
const dsl = extractDsl(item?.json?.text);

return [{
  json: {
    designDsl: JSON.stringify(dsl),
    revisionNumber: Number(item?.json?.revisionNumber ?? 0) || 0,
  },
  ...(item?.binary && Object.keys(item.binary).length > 0 ? { binary: item.binary } : {}),
}];

