const json = item?.json ?? {};

function asDesignString(value) {
  if (typeof value === 'string' && value.trim()) return value.trim();
  if (value && typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch {}
  }
  return '';
}

let design = asDesignString(json.design);

if (!design && typeof $items === 'function') {
  const historyNodes = [
    'DESIGN - Compile DSL',
    'DESIGN - Build Image ZIP',
    'DESIGN - Prepare Information',
    'DESIGN - Prepare Information for First Iteration',
  ];

  for (const nodeName of historyNodes) {
    const nodeItems = $items(nodeName) || [];
    for (let i = nodeItems.length - 1; i >= 0; i -= 1) {
      const candidate = asDesignString(nodeItems[i]?.json?.design);
      if (candidate) {
        design = candidate;
        break;
      }
    }
    if (design) break;
  }
}

if (!design) {
  throw new Error('Final Excalidraw JSON was not found in execution context.');
}

return [{
  json: {
    ...json,
    finalDesignExcalidraw: design,
  },
  ...(item?.binary && Object.keys(item.binary).length > 0 ? { binary: item.binary } : {}),
}];
